#!/usr/bin/env python3
"""
cninfo 巨潮资讯网财报数据爬虫 - 单文件工具
===========================================
功能:
  - 单个 / 批量 / 年限区间 查询上市公司财报公告
  - 直接下载 PDF 年报
  - 可作为 CLI 工具或 import 模块调用

依赖: requests (仅一个第三方库)

用法示例:
  # CLI 模式
  python3 cninfo_finance.py 000001                    # 查平安银行所有年报
  python3 cninfo_finance.py 000001 --years 2023-2025  # 指定年限
  python3 cninfo_finance.py 000001,600519,000002 --years 2024  # 批量
  python3 cninfo_finance.py 000001 --download         # 下载PDF
  python3 cninfo_finance.py 000001 --category 半年报    # 查半年报

  # 模块调用
  from cninfo_finance import get_reports, download_pdfs
  reports = get_reports("000001", years=(2023, 2025))
  download_pdfs(reports, output_dir="./pdfs")
"""

import argparse
import base64
import gzip
import json
import os
import sys
import time
from datetime import datetime
from functools import lru_cache
from typing import Optional

import requests

# ─── 常量 ───────────────────────────────────────────────
BASE_URL = "http://www.cninfo.com.cn"
API_QUERY = f"{BASE_URL}/new/hisAnnouncement/query"
CDN_BASE = "http://static.cninfo.com.cn"
USER_AGENT = (
    "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
    "AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36"
)
HEADERS = {
    "User-Agent": USER_AGENT,
    "Referer": f"{BASE_URL}/new/commonUrl?url=disclosure/list/notice",
    "X-Requested-With": "XMLHttpRequest",
    "Accept": "application/json",
    "Content-Type": "application/x-www-form-urlencoded",
}

# 公告类别 → API 参数映射
CATEGORY_MAP = {
    "年报":      "category_ndbg_szsh",
    "半年报":    "category_bndbg_szsh",
    "一季报":    "category_yjdbg_szsh",
    "三季报":    "category_sjdbg_szsh",
    "业绩预告":  "category_yjyg_szsh",
    "业绩快报":  "category_yjkb_szsh",
    "招股说明书":"category_zssms_szsh",
    "配股说明书":"category_pgsms_szsh",
    "增发说明书":"category_zfsms_szsh",
    "权益变动":  "category_qybd_szsh",
    "股东大会":  "category_gddh_szsh",
    "董事会决议":"category_dshjy_szsh",
    "监事会决议":"category_jshjy_szsh",
}

DEFAULT_CATEGORY = "年报"
_delay_config = {"value": 1.0}  # mutable to allow runtime config without global keyword
PAGE_SIZE = 30


# ─── 内嵌股票映射 (gzip+base64 → code→orgId dict) ──────
# 原始数据来源: https://github.com/jingmian/cninfo_spider stock_info.json
# 更新方式: cninfo_finance.py --update-mapping
_STOCK_MAPPING_B64 = (
    ""
)

# 以下代码在运行时解压 stock mapping
def _load_stock_mapping() -> dict:
    """解压并返回 {code: orgId} 映射"""
    # 如果内嵌数据不完整，尝试从本地文件或远程加载
    try:
        if len(_STOCK_MAPPING_B64) < 1000:
            raise ValueError("Embedded mapping too short, loading from remote")
        compressed = base64.b64decode(_STOCK_MAPPING_B64)
        raw = gzip.decompress(compressed).decode("utf-8")
        return json.loads(raw)
    except Exception:
        return _load_remote_mapping()


def _load_remote_mapping() -> dict:
    """从 GitHub 远程加载 stock 映射，失败则返回空"""
    url = "https://raw.githubusercontent.com/jingmian/cninfo_spider/main/stock_info.json"
    try:
        resp = requests.get(url, timeout=15, headers={"User-Agent": USER_AGENT})
        resp.raise_for_status()
        data = resp.json()
        return {s["code"]: s["orgId"] for s in data.get("stockList", [])}
    except Exception:
        return {}


# ─── 核心 API ──────────────────────────────────────────
@lru_cache(maxsize=512)
def _get_org_id(stock_code: str) -> Optional[str]:
    """根据股票代码获取 cninfo 内部 orgId"""
    mapping = _stock_mapping
    if stock_code in mapping:
        return mapping[stock_code]

    # 降级：尝试公式推导
    code = stock_code.zfill(6)
    if code.startswith("6"):
        return f"gssh0{code}"
    elif code.startswith(("000", "001", "002", "003")):
        return f"gssz0{code}"
    return None


def get_reports(
    stock_code: str,
    years: Optional[tuple] = None,
    category: str = DEFAULT_CATEGORY,
    page_size: int = PAGE_SIZE,
    max_pages: int = 50,
) -> list[dict]:
    """
    获取单只股票的财报公告列表。

    Args:
        stock_code: 股票代码，如 "000001"
        years: 年份区间 (start, end)，如 (2023, 2025)；None 表示全部年份
        category: 公告类别，如 "年报" "半年报" "一季报" "三季报"
        page_size: 每页条数 (默认 30)
        max_pages: 最大翻页数 (防止无限循环)

    Returns:
        list[dict]: 公告列表，每个元素包含:
            secCode, secName, announcementId, announcementTitle,
            announcementTime (时间戳ms), adjunctUrl (PDF相对路径)
    """
    org_id = _get_org_id(stock_code)
    if org_id is None:
        print(f"[WARN] 未找到 {stock_code} 的 orgId，跳过", file=sys.stderr)
        return []

    cat_key = CATEGORY_MAP.get(category, CATEGORY_MAP[DEFAULT_CATEGORY])

    # 构建日期区间
    if years:
        start_date = f"{years[0]}-01-01"
        end_date = f"{years[1]}-12-31"
    else:
        start_date = "2000-01-01"
        end_date = datetime.now().strftime("%Y-%m-%d")

    stock_param = f"{stock_code},{org_id}"
    all_announcements = []

    for page in range(1, max_pages + 1):
        payload = {
            "pageNum": page,
            "pageSize": page_size,
            "stock": stock_param,
            "category": cat_key,
            "seDate": f"{start_date}~{end_date}",
            "column": "szse",
            "tabName": "fulltext",
        }

        try:
            resp = requests.post(API_QUERY, data=payload, headers=HEADERS, timeout=30)
            resp.raise_for_status()
            data = resp.json()
        except Exception as e:
            print(f"[ERROR] 查询失败 (page={page}): {e}", file=sys.stderr)
            break

        announcements = data.get("announcements") or []
        if not announcements:
            break

        all_announcements.extend(announcements)

        if not data.get("hasMore"):
            break

        time.sleep(_delay_config["value"])

    return all_announcements


def get_reports_batch(
    stock_codes: list[str],
    years: Optional[tuple] = None,
    category: str = DEFAULT_CATEGORY,
    **kwargs,
) -> dict[str, list[dict]]:
    """
    批量获取多只股票的财报公告。

    Args:
        stock_codes: 股票代码列表
        years: 年份区间，同上
        category: 公告类别

    Returns:
        dict: {stock_code: [announcements]}
    """
    results = {}
    for i, code in enumerate(stock_codes):
        print(f"[{i+1}/{len(stock_codes)}] 正在查询 {code}...", file=sys.stderr)
        results[code] = get_reports(code, years=years, category=category, **kwargs)
        if i < len(stock_codes) - 1:
            time.sleep(_delay_config["value"])
    return results


def download_pdf(
    adjunct_url: str,
    output_dir: str = "./pdfs",
    filename: Optional[str] = None,
    timeout: int = 120,
) -> Optional[str]:
    """
    下载单个 PDF 文件。

    Args:
        adjunct_url: 公告中的 adjunctUrl 字段，如 "finalpage/2026-03-21/1225022887.PDF"
        output_dir:  输出目录
        filename:    自定义文件名；不传则从 URL 提取
        timeout:     下载超时 (秒)

    Returns:
        保存路径 或 None (失败时)
    """
    os.makedirs(output_dir, exist_ok=True)

    if filename is None:
        filename = os.path.basename(adjunct_url)
        if not filename.lower().endswith(".pdf"):
            filename += ".pdf"

    filepath = os.path.join(output_dir, filename)

    if os.path.exists(filepath):
        print(f"[SKIP] 文件已存在: {filepath}", file=sys.stderr)
        return filepath

    url = f"{CDN_BASE}/{adjunct_url}"
    dl_headers = {
        "User-Agent": USER_AGENT,
        "Referer": f"{BASE_URL}/",
    }

    try:
        resp = requests.get(url, headers=dl_headers, timeout=timeout, stream=True)
        resp.raise_for_status()

        total = int(resp.headers.get("Content-Length", 0))
        downloaded = 0

        with open(filepath, "wb") as f:
            for chunk in resp.iter_content(chunk_size=8192):
                f.write(chunk)
                downloaded += len(chunk)

        if total > 0 and downloaded < total * 0.95:
            os.remove(filepath)
            print(f"[ERROR] 下载不完整: {filename}", file=sys.stderr)
            return None

        return filepath

    except Exception as e:
        if os.path.exists(filepath):
            os.remove(filepath)
        print(f"[ERROR] 下载失败: {filename} - {e}", file=sys.stderr)
        return None


def download_pdfs(
    announcements: list[dict],
    output_dir: str = "./pdfs",
    stock_code: Optional[str] = None,
) -> list[str]:
    """
    批量下载公告 PDF。

    Args:
        announcements: get_reports() 返回的公告列表
        output_dir:   输出根目录 (会自动按股票代码建子目录)
        stock_code:   股票代码 (若不传，从公告中自动提取)

    Returns:
        成功下载的文件路径列表
    """
    results = []
    for ann in announcements:
        adjunct_url = ann.get("adjunctUrl")
        if not adjunct_url:
            continue

        code = stock_code or ann.get("secCode", "unknown")
        title = ann.get("announcementTitle", "unknown").replace("/", "_")
        subdir = os.path.join(output_dir, code)
        os.makedirs(subdir, exist_ok=True)

        base_name = os.path.basename(adjunct_url)
        filename = f"{title}_{base_name}" if not base_name.lower().endswith(".pdf") else f"{title}.pdf"

        path = download_pdf(adjunct_url, output_dir=subdir, filename=filename)
        if path:
            results.append(path)
        time.sleep(0.5)  # 下载间隔

    return results


def download_pdfs_batch(
    batch_results: dict[str, list[dict]],
    output_dir: str = "./pdfs",
) -> dict[str, list[str]]:
    """
    批量下载多只股票的 PDF。

    Args:
        batch_results: get_reports_batch() 的返回值
        output_dir:   输出根目录

    Returns:
        {stock_code: [downloaded_paths]}
    """
    results = {}
    total_codes = len(batch_results)
    for i, (code, announcements) in enumerate(batch_results.items()):
        print(f"\n[{i+1}/{total_codes}] 下载 {code} 的 PDF ({len(announcements)} 份)...", file=sys.stderr)
        results[code] = download_pdfs(announcements, output_dir, stock_code=code)
    return results


def update_stock_mapping(output_path: Optional[str] = None) -> dict:
    """
    更新股票代码 → orgId 映射 (从 GitHub 远程加载)。

    Args:
        output_path: 保存路径，不传则只返回不保存

    Returns:
        更新后的映射 dict
    """
    print("正在从 GitHub 下载最新 stock_info.json ...", file=sys.stderr)
    mapping = _load_remote_mapping()
    if mapping:
        print(f"成功获取 {len(mapping)} 条映射", file=sys.stderr)
        if output_path:
            with open(output_path, "w") as f:
                json.dump(mapping, f, ensure_ascii=False, indent=2)
            print(f"已保存到 {output_path}", file=sys.stderr)
    else:
        print("获取失败", file=sys.stderr)
    return mapping


# ─── 格式化输出 ─────────────────────────────────────────
def _format_time(ts_ms: int) -> str:
    """毫秒时间戳 → 日期字符串"""
    try:
        return datetime.fromtimestamp(ts_ms / 1000).strftime("%Y-%m-%d")
    except Exception:
        return str(ts_ms)


def _print_table(announcements: list[dict]) -> None:
    """以表格形式打印公告列表"""
    if not announcements:
        print("(无结果)")
        return

    print(f"\n{'代码':<8} {'公司':<12} {'日期':<12} {'标题'}")
    print("-" * 80)
    for a in announcements:
        code = a.get("secCode", "?")
        name = a.get("secName", "?")
        date = _format_time(a.get("announcementTime", 0))
        title = a.get("announcementTitle", "?")
        print(f"{code:<8} {name:<12} {date:<12} {title}")


# ─── CLI ────────────────────────────────────────────────
def main():
    parser = argparse.ArgumentParser(
        description="cninfo 巨潮资讯网财报爬虫",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
示例:
  %(prog)s 000001                          # 查询平安银行所有年报
  %(prog)s 000001 --years 2023-2025        # 指定年份区间
  %(prog)s 000001,600519,000002 --years 2024    # 批量查询
  %(prog)s 000001 --download               # 下载PDF
  %(prog)s 000001 --download --years 2022-2024  # 下载指定年份PDF
  %(prog)s 000001 --category 半年报         # 查询半年报
  %(prog)s --update-mapping                 # 更新股票映射
        """,
    )
    parser.add_argument(
        "stocks", nargs="?", default=None,
        help="股票代码，多个用逗号分隔 (如 000001,600519,000002)"
    )
    parser.add_argument(
        "--years", "-y", default=None,
        help="年份区间: 2023-2025 或 2024 (单年)"
    )
    parser.add_argument(
        "--category", "-c", default=DEFAULT_CATEGORY,
        choices=list(CATEGORY_MAP.keys()),
        help=f"公告类别 (默认: {DEFAULT_CATEGORY})"
    )
    parser.add_argument(
        "--download", "-d", action="store_true",
        help="下载 PDF 文件"
    )
    parser.add_argument(
        "--output", "-o", default="./pdfs",
        help="PDF 输出目录 (默认: ./pdfs)"
    )
    parser.add_argument(
        "--json", "-j", action="store_true",
        help="以 JSON 格式输出"
    )
    parser.add_argument(
        "--update-mapping", action="store_true",
        help="更新内嵌的股票代码映射"
    )
    parser.add_argument(
        "--delay", type=float, default=_delay_config["value"],
        help=f"请求间隔秒数 (默认: {_delay_config['value']})"
    )

    args = parser.parse_args()

    # 设置请求延迟
    _delay_config["value"] = args.delay

    # 更新映射
    if args.update_mapping:
        mapping = update_stock_mapping()
        if mapping:
            # 生成压缩数据提示
            json_str = json.dumps(mapping, separators=(",", ":"))
            compressed = gzip.compress(json_str.encode())
            b64 = base64.b64encode(compressed).decode()
            print(f"\n压缩后 Base64 长度: {len(b64)} 字节", file=sys.stderr)
            print("可将其替换脚本中的 _STOCK_MAPPING_B64 变量", file=sys.stderr)
        return

    # 需要股票代码
    if not args.stocks:
        parser.print_help()
        return

    # 解析年份
    years = None
    if args.years:
        parts = args.years.split("-")
        if len(parts) == 1:
            y = int(parts[0])
            years = (y, y)
        elif len(parts) == 2:
            years = (int(parts[0]), int(parts[1]))
        else:
            print("年份格式错误，请使用: YYYY 或 YYYY-YYYY", file=sys.stderr)
            return

    # 解析股票列表
    codes = [c.strip() for c in args.stocks.split(",") if c.strip()]

    # 查询
    if len(codes) == 1:
        reports = get_reports(codes[0], years=years, category=args.category)
        results = {codes[0]: reports}
    else:
        results = get_reports_batch(codes, years=years, category=args.category)

    # 输出
    for code, reports in results.items():
        if args.json:
            print(json.dumps(reports, ensure_ascii=False, indent=2))
        else:
            print(f"\n{'='*60}")
            print(f"  {code} | {args.category} | {args.years or '全部年份'} | 共 {len(reports)} 条")
            print(f"{'='*60}")
            _print_table(reports)

    # 下载
    if args.download:
        all_announcements = []
        for reports in results.values():
            all_announcements.extend(reports)
        if all_announcements:
            print(f"\n开始下载 {len(all_announcements)} 份 PDF 到 {args.output} ...", file=sys.stderr)
            paths = download_pdfs_batch(results, output_dir=args.output)
            total = sum(len(v) for v in paths.values())
            print(f"\n下载完成: {total} 份 PDF", file=sys.stderr)


# ─── 模块初始化 ─────────────────────────────────────────
_stock_mapping = _load_stock_mapping()

# 如果内嵌映射不完整，运行时自动从远程加载
if len(_stock_mapping) < 100:
    _stock_mapping = _load_remote_mapping()


if __name__ == "__main__":
    main()
